import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { useForm } from 'react-hook-form';
import { Phone, Mail, MapPin, Clock, Send, CheckCircle } from 'lucide-react';
import toast from 'react-hot-toast';

const ContactPage = () => {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  
  const {
    register,
    handleSubmit,
    formState: { errors },
    reset
  } = useForm();

  const contactInfo = [
    {
      icon: Phone,
      title: '电话咨询',
      details: ['400-123-4567', '周一至周日 8:00-22:00'],
      color: 'bg-blue-600'
    },
    {
      icon: Mail,
      title: '邮件咨询',
      details: ['service@swiftfixpro.com', '24小时内回复'],
      color: 'bg-green-600'
    },
    {
      icon: MapPin,
      title: '公司地址',
      details: ['北京市朝阳区', '科技园区A座1001室'],
      color: 'bg-purple-600'
    },
    {
      icon: Clock,
      title: '工作时间',
      details: ['周一至周五: 9:00-18:00', '周六至周日: 10:00-16:00'],
      color: 'bg-orange-600'
    }
  ];

  const onSubmit = async (data) => {
    setIsSubmitting(true);
    
    // 模拟API调用
    await new Promise(resolve => setTimeout(resolve, 2000));
    
    console.log('Contact form data:', data);
    toast.success('消息已发送！我们会尽快回复您。');
    setIsSubmitted(true);
    setIsSubmitting(false);
    reset();
    
    // 3秒后重置提交状态
    setTimeout(() => setIsSubmitted(false), 3000);
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hero Section */}
      <section className="bg-gradient-to-r from-blue-600 to-purple-600 text-white py-20">
        <div className="container mx-auto px-4">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="text-center"
          >
            <h1 className="text-4xl md:text-5xl font-bold mb-6">
              联系我们
            </h1>
            <p className="text-xl mb-8 max-w-2xl mx-auto">
              我们随时准备为您提供帮助。如果您有任何问题或需要咨询，请随时联系我们。
            </p>
          </motion.div>
        </div>
      </section>

      {/* Contact Info Section */}
      <section className="py-16 bg-white">
        <div className="container mx-auto px-4">
          <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-8">
            {contactInfo.map((info, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.6, delay: index * 0.1 }}
                className="text-center p-6 rounded-lg bg-gray-50 hover:bg-gray-100 transition-colors"
              >
                <div className={`inline-flex items-center justify-center w-16 h-16 ${info.color} text-white rounded-full mb-4`}>
                  <info.icon size={24} />
                </div>
                <h3 className="text-xl font-semibold mb-3">{info.title}</h3>
                {info.details.map((detail, i) => (
                  <p key={i} className="text-gray-600 mb-1">
                    {detail}
                  </p>
                ))}
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* Contact Form and Map Section */}
      <section className="py-16">
        <div className="container mx-auto px-4">
          <div className="grid lg:grid-cols-2 gap-12">
            {/* Contact Form */}
            <motion.div
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.6 }}
              className="bg-white p-8 rounded-lg shadow-lg"
            >
              <h2 className="text-3xl font-bold mb-6">发送消息</h2>
              
              {isSubmitted ? (
                <motion.div
                  initial={{ opacity: 0, scale: 0.8 }}
                  animate={{ opacity: 1, scale: 1 }}
                  className="text-center py-8"
                >
                  <CheckCircle className="w-16 h-16 text-green-500 mx-auto mb-4" />
                  <h3 className="text-2xl font-semibold mb-2">消息已发送！</h3>
                  <p className="text-gray-600">感谢您的留言，我们会尽快回复您。</p>
                </motion.div>
              ) : (
                <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
                  <div className="grid md:grid-cols-2 gap-6">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        姓名 *
                      </label>
                      <input
                        type="text"
                        {...register('name', { required: '请输入姓名' })}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                        placeholder="请输入您的姓名"
                      />
                      {errors.name && (
                        <p className="text-red-500 text-sm mt-1">{errors.name.message}</p>
                      )}
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        电话 *
                      </label>
                      <input
                        type="tel"
                        {...register('phone', { 
                          required: '请输入电话号码',
                          pattern: {
                            value: /^1[3-9]\d{9}$/,
                            message: '请输入有效的手机号码'
                          }
                        })}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                        placeholder="请输入您的电话号码"
                      />
                      {errors.phone && (
                        <p className="text-red-500 text-sm mt-1">{errors.phone.message}</p>
                      )}
                    </div>
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      邮箱 *
                    </label>
                    <input
                      type="email"
                      {...register('email', { 
                        required: '请输入邮箱地址',
                        pattern: {
                          value: /^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i,
                          message: '请输入有效的邮箱地址'
                        }
                      })}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                      placeholder="请输入您的邮箱地址"
                    />
                    {errors.email && (
                      <p className="text-red-500 text-sm mt-1">{errors.email.message}</p>
                    )}
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      主题 *
                    </label>
                    <select
                      {...register('subject', { required: '请选择咨询主题' })}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    >
                      <option value="">请选择咨询主题</option>
                      <option value="service">服务咨询</option>
                      <option value="product">产品咨询</option>
                      <option value="booking">预约服务</option>
                      <option value="complaint">投诉建议</option>
                      <option value="cooperation">商务合作</option>
                      <option value="other">其他</option>
                    </select>
                    {errors.subject && (
                      <p className="text-red-500 text-sm mt-1">{errors.subject.message}</p>
                    )}
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      消息内容 *
                    </label>
                    <textarea
                      {...register('message', { 
                        required: '请输入消息内容',
                        minLength: {
                          value: 10,
                          message: '消息内容至少需要10个字符'
                        }
                      })}
                      rows={6}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                      placeholder="请详细描述您的需求或问题..."
                    />
                    {errors.message && (
                      <p className="text-red-500 text-sm mt-1">{errors.message.message}</p>
                    )}
                  </div>

                  <button
                    type="submit"
                    disabled={isSubmitting}
                    className="w-full bg-blue-600 text-white py-3 px-6 rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                  >
                    {isSubmitting ? (
                      <>
                        <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                        发送中...
                      </>
                    ) : (
                      <>
                        <Send size={20} />
                        发送消息
                      </>
                    )}
                  </button>
                </form>
              )}
            </motion.div>

            {/* Map and Additional Info */}
            <motion.div
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.6 }}
              className="space-y-8"
            >
              {/* Map */}
              <div className="bg-white p-6 rounded-lg shadow-lg">
                <h3 className="text-xl font-semibold mb-4">公司位置</h3>
                <div className="bg-gray-200 h-64 rounded-lg flex items-center justify-center">
                  <p className="text-gray-500">地图组件将在这里显示</p>
                </div>
                <p className="text-sm text-gray-600 mt-2">
                  北京市朝阳区科技园区A座1001室
                </p>
              </div>

              {/* FAQ */}
              <div className="bg-white p-6 rounded-lg shadow-lg">
                <h3 className="text-xl font-semibold mb-4">常见问题</h3>
                <div className="space-y-4">
                  <div>
                    <h4 className="font-medium text-gray-800 mb-2">
                      如何预约服务？
                    </h4>
                    <p className="text-sm text-gray-600">
                      您可以通过我们的网站、电话或邮件预约服务。我们会安排专业团队在约定时间为您提供服务。
                    </p>
                  </div>
                  <div>
                    <h4 className="font-medium text-gray-800 mb-2">
                      服务费用如何计算？
                    </h4>
                    <p className="text-sm text-gray-600">
                      服务费用根据服务类型、工作量和材料成本计算。我们会提供详细的报价单，确保费用透明。
                    </p>
                  </div>
                  <div>
                    <h4 className="font-medium text-gray-800 mb-2">
                      是否提供紧急服务？
                    </h4>
                    <p className="text-sm text-gray-600">
                      是的，我们提供24/7紧急服务。对于紧急情况，我们会优先安排处理。
                    </p>
                  </div>
                </div>
              </div>
            </motion.div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default ContactPage;
